import*as React from"react";export default function mergeRefs(){for(var e=arguments.length,n=new Array(e),r=0;r<e;r++)n[r]=arguments[r];return function(r){n.forEach(e=>{null!=e&&("function"==typeof e?e(r):"object"==typeof e?e.current=r:console.error("mergeRefs cannot handle Refs of type boolean, number or string, received ref "+String(e)))})}}